const a = [
  {"id":1689,"text":"Which of the following is not a feature of a life-threatening condition in asthma?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 572.","responses":[{"text":"Respiratory rate \u003e 25/min","correct":true,"visible":false},{"text":"Hypotension","correct":false,"visible":false},{"text":"Confusion","correct":false,"visible":false},{"text":"Silent chest","correct":false,"visible":false},{"text":"Bradycardia","correct":false,"visible":false}]},{"id":1690,"text":"A 24-year-old patient presents to the emergency room with acute exacerbation of asthma. He is tachycardic and is unable to complete a sentence in 1 breath. Oxygen therapy is given. What should be the next step in his management regimen?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 572.","responses":[{"text":"Intravenous fluids","correct":false,"visible":false},{"text":"Formoterol","correct":false,"visible":false},{"text":"Salmeterol","correct":false,"visible":false},{"text":"Potassium supplements","correct":false,"visible":false},{"text":"Salbutamol","correct":true,"visible":false}]},{"id":1691,"text":"Spirometry is being performed on a patient. The results show a reduced FEV1/FVC and an increased residual volume. Which of the following is the most likely cause?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 698.","responses":[{"text":"Asthma","correct":true,"visible":false},{"text":"Idiopathic pulmonary fibrosis","correct":false,"visible":false},{"text":"Sarcoidosis","correct":false,"visible":false},{"text":"Asbestosis","correct":false,"visible":false},{"text":"Cystic fibrosis","correct":false,"visible":false}]},{"id":1692,"text":"Which of the following will not be a clinical finding in chronic obstructive pulmonary disease (COPD)?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 91.","responses":[{"text":"Wheezing","correct":false,"visible":false},{"text":"Weight loss","correct":false,"visible":false},{"text":"Splenomegaly","correct":true,"visible":false},{"text":"Cough with sputum","correct":false,"visible":false},{"text":"Breathing through pursed lips","correct":false,"visible":false}]},{"id":1693,"text":"Which obstructive lung disease is characterized by a low diffusing capacity of the lung for carbon monoxide (DLCO)?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 698.","responses":[{"text":"Emphysema","correct":true,"visible":false},{"text":"Interstitial lung disease","correct":false,"visible":false},{"text":"Bronchitis","correct":false,"visible":false},{"text":"Asthma","correct":false,"visible":false},{"text":"Sarcoidosis","correct":false,"visible":false}]},{"id":1695,"text":"T-helper 2 (TH2) cell's response in asthma recruits which of the following cells?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 91.","responses":[{"text":"Erythrocytes","correct":false,"visible":false},{"text":"Macrophages","correct":false,"visible":false},{"text":"Basophils","correct":false,"visible":false},{"text":"Eosinophils","correct":true,"visible":false},{"text":"Neutrophils","correct":false,"visible":false}]},{"id":1696,"text":"Which antibody is increased in atopic asthma?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 91.","responses":[{"text":"IgG","correct":false,"visible":false},{"text":"IgA","correct":false,"visible":false},{"text":"IgE","correct":true,"visible":false},{"text":"IgM","correct":false,"visible":false},{"text":"IgD","correct":false,"visible":false}]},{"id":1697,"text":"Emphysema is characterized by which of the following?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 90.","responses":[{"text":"Smooth muscle hyperplasia","correct":false,"visible":false},{"text":"Inflammatory scarring","correct":false,"visible":false},{"text":"Alveolar damage","correct":true,"visible":false},{"text":"Permanent airway dilatation and scarring","correct":false,"visible":false},{"text":"Bronchoconstriction","correct":false,"visible":false}]},{"id":1698,"text":"Bronchiectasis is characterized by which of the following?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 91.","responses":[{"text":"Bronchoconstriction","correct":false,"visible":false},{"text":"Inflammatory scarring","correct":false,"visible":false},{"text":"Smooth muscle hyperplasia","correct":false,"visible":false},{"text":"Permanent airway dilatation","correct":true,"visible":false},{"text":"Alveolar damage","correct":false,"visible":false}]},{"id":1699,"text":"'Eggshell' calcification in the hilar lymph nodes is a feature of which of the following?","explanation":"The **'eggshell' calcification** in the hilar lymph nodes is a characteristic feature of silicosis.\r\n\r\n**Silicosis** is a form of pneumoconiosis caused by inhalation of crystalline silica particles, commonly found in occupations such as mining, sandblasting, and construction. Over time, these inhaled particles lead to the formation of fibrotic nodules in the lungs, known as silicotic nodules. In some cases, these nodules may undergo calcification, particularly in the hilar lymph nodes.\r\n\r\nThe term 'eggshell' calcification refers to a thin layer of calcification surrounding the hilar lymph nodes, which can be visualized on imaging studies such as chest X-rays or computed tomography (CT) scans. The presence of this characteristic calcification pattern in the hilar lymph nodes is strongly suggestive of silicosis.","reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 702.","responses":[{"text":"Asbestosis","correct":false,"visible":false},{"text":"Berylliosis","correct":false,"visible":false},{"text":"Byssinosis","correct":false,"visible":false},{"text":"Silicosis","correct":true,"visible":false},{"text":"Anthracosis","correct":false,"visible":false}]},{"id":1722,"text":"Which of the following drugs is a 5-lipoxygenase pathway inhibitor?","explanation":"The drug **zileuton** is a 5-lipoxygenase pathway inhibitor. The 5-lipoxygenase pathway plays a crucial role in the production of leukotrienes, which are inflammatory mediators involved in various allergic and inflammatory conditions, including asthma.\r\nBy blocking this pathway, it helps to alleviate inflammation and bronchoconstriction in conditions such as asthma.\r\n\r\nUnlike other asthma medications that primarily target bronchodilation or inflammation, Zileuton specifically targets the 5-lipoxygenase pathway, providing an alternative approach to managing asthma symptoms. It is usually prescribed as an adjunct therapy in patients who require additional control of their asthma symptoms despite using other asthma medications.","reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 712.","responses":[{"text":"Cromolyn","correct":false,"visible":false},{"text":"Zileuton","correct":true,"visible":false},{"text":"Monteluklast","correct":false,"visible":false},{"text":"Theophylline","correct":false,"visible":false},{"text":"Omalizumab","correct":false,"visible":false}]},{"id":1726,"text":"Which of the following is not a centrally acting antitussive?","explanation":null,"reference":"Whalen K, Finkel R, Panavelil TA. Lippincott Illustrated Reviews: Pharmacology. 6th ed. Lippincott Williams \u0026 Wilkins; 2015: 197, 390.","responses":[{"text":"Opioids","correct":false,"visible":false},{"text":"Dextromethorphan","correct":false,"visible":false},{"text":"Hydrocodone","correct":false,"visible":false},{"text":"Inhaled steam","correct":true,"visible":false},{"text":"Codeine","correct":false,"visible":false}]},{"id":1744,"text":"Postmortem lividity is fully established by how many hours after death?","explanation":null,"reference":"Almulhim AM, Menezes RG. Evaluation of postmortem changes. In: StatPearls. StatPearls Publishing; 2022. Accessed April 17, 2022. http://www.ncbi.nlm.nih.gov/books/NBK554464/","responses":[{"text":"24-72 hours","correct":false,"visible":false},{"text":"6-8 hours","correct":true,"visible":false},{"text":"24 hours","correct":false,"visible":false},{"text":"3-6 hours","correct":false,"visible":false},{"text":"1-3 hours","correct":false,"visible":false}]},{"id":1750,"text":"What kind of emphysema occurs in coal workers pneumoconiosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n689.","responses":[{"text":"Interstitial","correct":false,"visible":false},{"text":"Panacinar","correct":false,"visible":false},{"text":"Paraseptal","correct":false,"visible":false},{"text":"Diffuse","correct":false,"visible":false},{"text":"Centriacinar","correct":true,"visible":false}]},{"id":1752,"text":"Which chemotherapeutic agent may cause pulmonary fibrosis?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 252.","responses":[{"text":"Bleomycin","correct":true,"visible":false},{"text":"Paclitaxel","correct":false,"visible":false},{"text":"Vincristine","correct":false,"visible":false},{"text":"Cladribine","correct":false,"visible":false},{"text":"Cyclophosphamide","correct":false,"visible":false}]},{"id":1753,"text":"Exposure to asbestos will not lead to which of the following?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 702.","responses":[{"text":"Mesothelioma","correct":false,"visible":false},{"text":"Pleural effusion","correct":false,"visible":false},{"text":"Asthma","correct":true,"visible":false},{"text":"Bronchogenic cancer","correct":false,"visible":false},{"text":"Interstitial fibrosis","correct":false,"visible":false}]},{"id":1754,"text":"Which HLA haplotypes are involved in the development of sarcoidosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n693.","responses":[{"text":"HLA-B7 and HLA-A1","correct":false,"visible":false},{"text":"HLA-B8 and HLA-A1","correct":true,"visible":false},{"text":"HLA-B38 and HLA-B8","correct":false,"visible":false},{"text":"HLA-B27 and HLA-B7","correct":false,"visible":false},{"text":"HLA-DRB1 and HLA-B8","correct":false,"visible":false}]},{"id":1755,"text":"Chronic exposure to organic dust leads to which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n694.","responses":[{"text":"Tuberculosis","correct":false,"visible":false},{"text":"Hypersensitivity pneumonitis","correct":true,"visible":false},{"text":"Interstitial lung disease","correct":false,"visible":false},{"text":"Asthma","correct":false,"visible":false},{"text":"Pneumonia","correct":false,"visible":false}]},{"id":1756,"text":"The radiograph of a 31-year-old patient shows bilateral reticulonodular opacities in the subpleural regions of the lower lobes. What is the most likely diagnosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015:  686.","responses":[{"text":"Chronic bronchitis","correct":false,"visible":false},{"text":"Bronchial asthma","correct":false,"visible":false},{"text":"Congestive heart failure","correct":false,"visible":false},{"text":"Idiopathic pulmonary fibrosis","correct":true,"visible":false},{"text":"Pulmonary embolism","correct":false,"visible":false}]},{"id":1759,"text":"Which of the following is the most common occupational lung disease?","explanation":null,"reference":"(1) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 692.\r\n\r\n(2) Silicosis - an overview | sciencedirect topics. Accessed April 22, 2022. https://www.sciencedirect.com/topics/medicine-and-dentistry/silicosis","responses":[{"text":"Farmer's lung","correct":false,"visible":false},{"text":"Asbestosis","correct":false,"visible":false},{"text":"Asymptomatic anthracosis","correct":false,"visible":false},{"text":"Progressive massive fibrosis","correct":false,"visible":false},{"text":"Silicosis","correct":true,"visible":false}]},{"id":1764,"text":"Which of the following is the most common cancer that can metastasize to the lung?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 96.","responses":[{"text":"Breast cancer","correct":true,"visible":false},{"text":"Bone cancer","correct":false,"visible":false},{"text":"Prostate cancer","correct":false,"visible":false},{"text":"Liver cancer","correct":false,"visible":false},{"text":"Skin cancer","correct":false,"visible":false}]},{"id":1777,"text":"What is the cause of panacinar emphysema?","explanation":null,"reference":"(1) Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 90.\r\n\r\n(2) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 675.","responses":[{"text":"Past severe infection","correct":false,"visible":false},{"text":"Exposure to air pollutants","correct":false,"visible":false},{"text":"Alpha-1 antitrypsin deficiency","correct":true,"visible":false},{"text":"Excessive smoking","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false}]},{"id":1785,"text":"Which of the following is the major air pollutant of indoor smoke?","explanation":null,"reference":"Respiratory module, Community-medicine lecture slides, Topic: Air pollution, Sub-topic: Indoor air pollution.","responses":[{"text":"Carbon monoxide","correct":true,"visible":false},{"text":"Nitrogen dioxide","correct":false,"visible":false},{"text":"Sulphur dioxide","correct":false,"visible":false},{"text":"Nitrous oxide","correct":false,"visible":false},{"text":"Carbon dioxide","correct":false,"visible":false}]},{"id":1793,"text":"Radiation hazard most commonly leads to which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n57.","responses":[{"text":"Death due to chronic liver failure","correct":false,"visible":false},{"text":"Coronary artery diseases","correct":false,"visible":false},{"text":"Leukemia only","correct":false,"visible":false},{"text":"Shortening of life always","correct":false,"visible":false},{"text":"Genetic changes and malformations","correct":true,"visible":false}]},{"id":1795,"text":"Bronchiectasis is associated with which of the following syndromes?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 91.","responses":[{"text":"Broken heart syndrome","correct":false,"visible":false},{"text":"Reye's syndrome","correct":false,"visible":false},{"text":"Turner's syndrome","correct":false,"visible":false},{"text":"Down syndrome","correct":false,"visible":false},{"text":"Kartagener's syndrome","correct":true,"visible":false}]},{"id":1796,"text":"A 54-year-old man with obesity marks on his abdomen presents with dyspnea and chest pain. He has a history of paraneoplastic syndrome. After suitable investigations, the doctor diagnoses him with lung cancer. Which type of lung cancer is most likely present in this patient?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 96.","responses":[{"text":"Adenocarcinoma","correct":false,"visible":false},{"text":"Small cell carcinoma","correct":true,"visible":false},{"text":"Large cell carcinoma","correct":false,"visible":false},{"text":"Carcinoid tumor","correct":false,"visible":false},{"text":"Squamous cell carcinoma","correct":false,"visible":false}]},{"id":1797,"text":"How many gross stages are there in lobar pneumonia?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 87.","responses":[{"text":"4","correct":true,"visible":false},{"text":"5","correct":false,"visible":false},{"text":"3","correct":false,"visible":false},{"text":"2","correct":false,"visible":false},{"text":"6","correct":false,"visible":false}]},{"id":1801,"text":"Which of the following is not associated with sarcoidosis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 93.","responses":[{"text":"Arthralgia","correct":false,"visible":false},{"text":"Hypocalcemia","correct":true,"visible":false},{"text":"Cranial nerve palsies","correct":false,"visible":false},{"text":"Cardiac arrhythmias","correct":false,"visible":false},{"text":"Erythema nodosum","correct":false,"visible":false}]},{"id":1802,"text":"What is the hematogenous dissemination of Mycobacterium tuberculosis called?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n373.","responses":[{"text":"Miliary tuberculosis","correct":true,"visible":false},{"text":"Tuberculosis lymphadenitis","correct":false,"visible":false},{"text":"Potts disease","correct":false,"visible":false},{"text":"Primary tuberculosis","correct":false,"visible":false},{"text":"Secondary tuberculosis","correct":false,"visible":false}]},{"id":1804,"text":"What is the causative organism of intestinal tuberculosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n371.","responses":[{"text":"Mycobacterium avium-intracellulare","correct":false,"visible":false},{"text":"Mycobacterium leprae","correct":false,"visible":false},{"text":"Mycobacterium bovis","correct":true,"visible":false},{"text":"Mycobacterium tuberculosis","correct":false,"visible":false},{"text":"Escherichia coli","correct":false,"visible":false}]},{"id":1805,"text":"First changes of tuberculosis occur in which region of the lungs?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 89.","responses":[{"text":"Throughout the lung","correct":false,"visible":false},{"text":"Middle lobe","correct":false,"visible":false},{"text":"Hilar lymph nodes","correct":false,"visible":false},{"text":"Upper lobe","correct":false,"visible":false},{"text":"Lower lobe","correct":true,"visible":false}]},{"id":1806,"text":"In small cell carcinoma, 50-80% mutations are present in which of the following genes?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n714.","responses":[{"text":"EGFR","correct":false,"visible":false},{"text":"TTF1","correct":false,"visible":false},{"text":"TP53","correct":true,"visible":false},{"text":"Chromogranin","correct":false,"visible":false},{"text":"P/6","correct":false,"visible":false}]},{"id":1807,"text":"Which of the following is not associated with chronic obstructive pulmonary disease (COPD)?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 574.","responses":[{"text":"Osteoporosis","correct":false,"visible":false},{"text":"Depression","correct":false,"visible":false},{"text":"Muscle wasting","correct":false,"visible":false},{"text":"Chronic liver disease","correct":true,"visible":false},{"text":"Metabolic syndrome","correct":false,"visible":false}]},{"id":1808,"text":"Which of the following histological findings will be observed in sarcoidosis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 92.","responses":[{"text":"Caseating granuloma","correct":false,"visible":false},{"text":"Non-caseating granuloma","correct":true,"visible":false},{"text":"Tuberculoma","correct":false,"visible":false},{"text":"Bird-beak appearance","correct":false,"visible":false},{"text":"Coin lesions","correct":false,"visible":false}]},{"id":1809,"text":"A medical student was studying a biopsy slide of a lung cancer patient. He found cells that were chromogranin positive. Which type of cancer is this?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 96.","responses":[{"text":"Small cell carcinoma","correct":true,"visible":false},{"text":"Large cell carcinoma","correct":false,"visible":false},{"text":"Squamous cell carcinoma","correct":false,"visible":false},{"text":"Adenocarcinoma","correct":false,"visible":false},{"text":"Bronchioloalveolar carcinoma","correct":false,"visible":false}]},{"id":1822,"text":"What is the most common type of bronchogenic tumor?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 96.","responses":[{"text":"Adenocarcinoma","correct":true,"visible":false},{"text":"Carcinoid tumor","correct":false,"visible":false},{"text":"Squamous cell carcinoma","correct":false,"visible":false},{"text":"Small cell carcinoma","correct":false,"visible":false},{"text":"Large cell carcinoma","correct":false,"visible":false}]},{"id":1823,"text":"What is the most common causative organism of gram-negative nosocomial pneumonia?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n703.","responses":[{"text":"Pseudomonas aeruginosa","correct":true,"visible":false},{"text":"Staphylococcus aureus","correct":false,"visible":false},{"text":"Mycoplasma pneumoniae","correct":false,"visible":false},{"text":"Klebsiella pneumoniae","correct":false,"visible":false},{"text":"Streptococcus pneumoniae","correct":false,"visible":false}]},{"id":1824,"text":"A forensic pathologist was working in his lab. On autopsy, he saw dilation and scarring of bronchi and bronchioles. What is the most likely diagnosis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 91.","responses":[{"text":"Bronchiectasis","correct":true,"visible":false},{"text":"Asthma","correct":false,"visible":false},{"text":"Pneumoconiosis","correct":false,"visible":false},{"text":"Brochiolitis","correct":false,"visible":false},{"text":"Emphysema","correct":false,"visible":false}]},{"id":1829,"text":"A patient with tuberculosis develops bright orange-red-urine and calls his physician in panic. The patient has no other urinary tract symptoms. Which of the following medication is most likely to produce this side effect?","explanation":null,"reference":"1) Katzung BG, ed. Basic \u0026 Clinical Pharmacology. 14th ed. McGraw Hill; 2018: 845.\r\n\r\n2) Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 193.","responses":[{"text":"Streptomycin","correct":false,"visible":false},{"text":"Pyridoxine","correct":false,"visible":false},{"text":"Ethambutol","correct":false,"visible":false},{"text":"Rifampin","correct":true,"visible":false},{"text":"Isoniazid","correct":false,"visible":false}]},{"id":1837,"text":"A 26-year-old housewife develops a high-grade fever, cough with purulent sputum, and pleuritic type of chest pain. The lady was previously in a good state of health. What is the most probable diagnosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n705.","responses":[{"text":"Bronchiectasis","correct":false,"visible":false},{"text":"Emphysema","correct":false,"visible":false},{"text":"Bacterial pneumonia","correct":true,"visible":false},{"text":"Pulmonary tuberculosis","correct":false,"visible":false},{"text":"Acute exacerbation of chronic bronchitis","correct":false,"visible":false}]},{"id":1839,"text":"A 4-year-old boy has a 1-month history of recurrent cough with wheezing. There is no history of previous similar complaints and no family history of asthma or tuberculosis. Examination shows enlarged cervical nodes and bronchi. Chest X-Ray shows air trapping on the right side during inspiration. Which of the following is the most likely diagnosis?","explanation":"In a 4-year-old boy with a 1-month history of recurrent cough with wheezing, enlarged cervical nodes, and findings of air trapping on chest X-ray, the most likely diagnosis is **foreign body aspiration**.\r\n\r\nForeign body aspiration occurs when a foreign object enters the airway and obstructs the bronchi, leading to respiratory symptoms such as cough, wheezing, and difficulty breathing. It commonly occurs in young children who tend to explore objects by putting them in their mouths.\r\n\r\nThe presence of wheezing and air trapping on the right side during inspiration suggests partial obstruction of the right main bronchus, causing air to be trapped in the affected lung segment.\r\n\r\nEnlarged cervical nodes may indicate reactive lymphadenopathy due to the presence of an inflammatory process in the airways.\r\n\r\nA thorough history, clinical examination, and imaging findings support the diagnosis of foreign body aspiration in this case. Prompt evaluation and appropriate intervention, such as bronchoscopy, are necessary to remove the foreign object and relieve the obstruction.","reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n669, 671, 683.","responses":[{"text":"Foreign body aspiration","correct":true,"visible":false},{"text":"Right middle lobe syndrome","correct":false,"visible":false},{"text":"Nodal tuberculosis","correct":false,"visible":false},{"text":"Reactive airway disease","correct":false,"visible":false},{"text":"Gastro esophageal reflux","correct":false,"visible":false}]},{"id":1841,"text":"A 3-year-old boy is brought with complaints of difficulty in breathing, noisy harsh sounds produced during inspiration, and high-grade fever for 2 days. What will be the most likely diagnosis?","explanation":"Based on the symptoms described (difficulty in breathing, noisy harsh sounds during inspiration, and high-grade fever), the most likely diagnosis in this case is **epiglottitis**. Epiglottitis is an inflammation of the epiglottis, a flap of tissue that covers the entrance of the trachea during swallowing to prevent food and liquid from entering the airway. It is commonly caused by a bacterial infection, most commonly by ***Haemophilus influenzae*** **type B (Hib)** bacteria.\r\n\r\nEpiglottitis is a serious condition that can rapidly progress and cause airway obstruction, leading to respiratory distress.","reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 85.","responses":[{"text":"Bacterial tracheitis","correct":false,"visible":false},{"text":"Foreign body inhalation","correct":false,"visible":false},{"text":"Laryngitis","correct":false,"visible":false},{"text":"Acute laryngotracheobronchitis (croup)","correct":false,"visible":false},{"text":"Epiglottitis","correct":true,"visible":false}]},{"id":1848,"text":"A 20-year-old thin, tall boy presented to the emergency room with sudden onset of cough, severe shortness of breath, and chest pain. He recently arrived from the USA after a 16-hour flight. Immediate chest X-Ray was advised with the suspicion of pneumothorax. Which chest examination finding best reveals pneumothorax?","explanation":"The finding that best reveals **pneumothorax** on chest examination is a hyper-resonant percussion note on the affected side.\r\n\r\nPercussion is a technique used to assess the underlying structures and air content in the lungs. In a normal lung, percussion produces a resonant sound. However, in the case of pneumothorax, where air accumulates in the pleural space, the affected lung becomes hyperinflated and less dense, resulting in a **hyper-resonant percussion note**. This means that the sound produced on percussion is louder and more resonant than expected.\r\n\r\nOther findings that may be present in pneumothorax include decreased breath sounds on auscultation on the affected side due to reduced air entry, and decreased chest movements on the affected side due to lung collapse.","reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 706.","responses":[{"text":"Increased breath sounds on auscultation on the affected side","correct":false,"visible":false},{"text":"Resonant percussion note on the affected side","correct":false,"visible":false},{"text":"Hyper-resonant percussion note on the affected side","correct":true,"visible":false},{"text":"Dull percussion note on the affected side","correct":false,"visible":false},{"text":"Increased chest movements on the affected side","correct":false,"visible":false}]},{"id":1850,"text":"A 28-year-old female came with acute shortness of breath for one day. She is experiencing night symptoms for the past 2 months. What is the cause of raised diffusion capacity for carbon monoxide (DLCO) in pulmonary function tests?","explanation":"DLCO measures the ability of the lungs to transfer carbon monoxide from inhaled air to the bloodstream. In **asthma**, the raised DLCO is attributed to increased ventilation-perfusion (V/Q) mismatch due to bronchoconstriction and airway inflammation. The airway inflammation causes a decrease in airway diameter and increased resistance, leading to airflow limitation and impaired ventilation. However, the alveolar-capillary membrane remains intact, allowing efficient gas exchange and resulting in an increased DLCO.\r\n\r\nIn conditions such as obstructive sleep apnea, emphysema, cardiac failure, and interstitial lung disease, the DLCO is usually reduced due to impaired gas exchange at the alveolar-capillary membrane. These conditions are associated with decreased lung compliance, structural lung abnormalities, and impaired diffusion capacity.","reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 699.","responses":[{"text":"Emphysema","correct":false,"visible":false},{"text":"Asthma","correct":true,"visible":false},{"text":"Obstructive sleep apnea","correct":false,"visible":false},{"text":"Cardiac failure","correct":false,"visible":false},{"text":"Interstitial lung disease","correct":false,"visible":false}]},{"id":1855,"text":"An elderly female is admitted to the intensive care unit (ICU) for acute respiratory distress syndrome on the 4th day of total hip replacement for a fracture of the neck of the femur. Which of the following is the cause of acute respiratory distress syndrome in this patient?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n672.","responses":[{"text":"Hemorrhage","correct":false,"visible":false},{"text":"Fat embolism","correct":true,"visible":false},{"text":"Disseminated intravascular coagulation","correct":false,"visible":false},{"text":"Infection","correct":false,"visible":false},{"text":"Thromboembolism","correct":false,"visible":false}]},{"id":1871,"text":"Malignant mesothelioma is associated with exposure to which of the following?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 25.","responses":[{"text":"Arsenic","correct":false,"visible":false},{"text":"Lead","correct":false,"visible":false},{"text":"Asbestos","correct":true,"visible":false},{"text":"Copper dust","correct":false,"visible":false},{"text":"Silica","correct":false,"visible":false}]},{"id":1884,"text":"Inhaled salbutamol is useful in bronchial asthma due to which of the following?","explanation":null,"reference":"Whalen K, Finkel R, Panavelil TA. Lippincott Illustrated Reviews: Pharmacology. 6th ed. Lippincott Williams \u0026 Wilkins; 2015: 88.","responses":[{"text":"Suppresses hyper-reactivity","correct":false,"visible":false},{"text":"Round the clock prophylaxis of asthma","correct":false,"visible":false},{"text":"Reduces inflammation","correct":false,"visible":false},{"text":"Status asthmaticus","correct":false,"visible":false},{"text":"Aborting/terminating asthma attacks","correct":true,"visible":false}]},{"id":1904,"text":"Rifampin is not indicated in which of the following conditions?","explanation":null,"reference":"(1) Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 139, 193. (2) Holland TL, Fowler VG. Rifampicin for Staphylococcus aureus bacteraemia: give it ARREST. The Lancet. Published February 17, 2018. Accessed May 12, 2022. https://www.thelancet.com/journals/lancet/article/PIIS0140-6736(17)33294-4/fulltext (3) Euba G, Murillo O, Fernández-Sabé N, et al. Long-term follow-up trial of oral rifampin-cotrimoxazole combination versus intravenous cloxacillin in treatment of chronic staphylococcal osteomyelitis. Antimicrobial Agents and Chemotherapy. Published June 2009. Accessed May 12, 2022. https://journals.asm.org/doi/10.1128/AAC.01504-08","responses":[{"text":"Endocarditis","correct":false,"visible":false},{"text":"Leprosy","correct":false,"visible":false},{"text":"Staphylococcus osteomyelitis","correct":false,"visible":false},{"text":"Hemophilus influenzae","correct":false,"visible":false},{"text":"Plaque","correct":true,"visible":false}]},{"id":1909,"text":"Which of the following is the most serious adverse event associated with ethambutol?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 194.","responses":[{"text":"Psychotic reaction","correct":false,"visible":false},{"text":"Optic neuritis","correct":true,"visible":false},{"text":"Nephritis","correct":false,"visible":false},{"text":"Hepatitis","correct":false,"visible":false},{"text":"Bone marrow suppression","correct":false,"visible":false}]},{"id":1918,"text":"Which of these is a life-saving drug given parenterally in severe status asthmaticus that will act by inhibiting phospholipase A2?","explanation":null,"reference":"Whalen K, Finkel R, Panavelil TA. Lippincott Illustrated Reviews: Pharmacology. 6th ed. Lippincott Williams \u0026 Wilkins; 2015: 384.","responses":[{"text":"Epinephrine","correct":false,"visible":false},{"text":"Salbutamol","correct":false,"visible":false},{"text":"Prednisone","correct":true,"visible":false},{"text":"Aminophylline","correct":false,"visible":false},{"text":"Metaproterenol","correct":false,"visible":false}]},{"id":1921,"text":"The type of asphyxia that is associated with anesthesia and surgical maneuvers is termed as:","explanation":"The type of asphyxia that is associated with anesthesia and surgical maneuvers is termed **iatrogenic asphyxia**. \"Iatrogenic\" refers to conditions or complications that are caused by medical intervention or treatment.\r\n\r\nDuring anesthesia and surgical procedures, there can be various factors that contribute to iatrogenic asphyxia. These may include airway obstruction, inadequate ventilation, or compromised oxygenation due to the effects of anesthesia or surgical manipulation.\r\n\r\nExamples of situations that can lead to iatrogenic asphyxia include the accidental placement of an endotracheal tube in the esophagus instead of the trachea, inadequate oxygen supply during surgery, or complications such as laryngospasm or bronchospasm.\r\n\r\nPrompt recognition and intervention are crucial in managing iatrogenic asphyxia to prevent severe respiratory compromise and potential adverse outcomes.","reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 161.","responses":[{"text":"Pathological asphyxia","correct":false,"visible":false},{"text":"Clinical asphyxia","correct":false,"visible":false},{"text":"Iatrogenic asphyxia","correct":true,"visible":false},{"text":"Mechanical asphyxia","correct":false,"visible":false},{"text":"Toxic asphyxia","correct":false,"visible":false}]},{"id":2211,"text":"Which of the following is not true about pneumonia?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 582, 585.","responses":[{"text":"It is an infectious disease","correct":false,"visible":false},{"text":"Bronchodilators are drug of choice for treatment","correct":true,"visible":false},{"text":"There is recently developed x-ray shadowing","correct":false,"visible":false},{"text":"It is an acute respiratory illness","correct":false,"visible":false},{"text":"Pleural effusion is a complication","correct":false,"visible":false}]},{"id":2214,"text":"What is the most common cause of lung abscess?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 708.","responses":[{"text":"Antecedent primary lung infection","correct":false,"visible":false},{"text":"Aspiration of infective material","correct":true,"visible":false},{"text":"Neoplasia","correct":false,"visible":false},{"text":"Septic embolism","correct":false,"visible":false},{"text":"Trauma","correct":false,"visible":false}]},{"id":2385,"text":"A body has been found hanging from a tree. The ligature mark runs obliquely on the neck and ecchymosis adjacent to the ligature mark on the neck muscle is found. This is the feature of:","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 166.","responses":[{"text":"Strangulation","correct":false,"visible":false},{"text":"Postmortem hanging","correct":false,"visible":false},{"text":"Ante-mortem hanging","correct":true,"visible":false},{"text":"Burking","correct":false,"visible":false},{"text":"Garroting","correct":false,"visible":false}]},{"id":2389,"text":"Mycobacteria do not get stained properly because of their high content of:","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 123.","responses":[{"text":"Calcium","correct":false,"visible":false},{"text":"Proteins","correct":false,"visible":false},{"text":"Carbohydrates","correct":false,"visible":false},{"text":"Lipids","correct":true,"visible":false},{"text":"Mannose","correct":false,"visible":false}]},{"id":2390,"text":"In a putrefied body death resulted from drowning, diatoms are found in which of the following organs/viscera?","explanation":"In cases of death resulting from drowning, the presence of diatoms in specific organs/viscera can be helpful in establishing the cause of death. Diatoms are microscopic aquatic organisms that can enter the body during submersion in water and become trapped in various tissues.\r\n\r\nThe correct answer is **Brain and bone marrow**. Diatoms can be found in the brain and bone marrow due to their high vascularity and ability to accumulate diatoms during the drowning process. The presence of diatoms in these tissues provides strong evidence supporting death by drowning.\r\n\r\n- Hilum of right lung and right ear: While diatoms can enter the respiratory system during drowning, they are not typically found in the hilum of the lung or the ear.\r\n- Stomach and left lung: Diatoms are not commonly found in the stomach or the left lung.\r\n- Gall bladder and liver: Diatoms do not typically accumulate in the gall bladder or the liver.\r\n- Ileum and under surface of liver: These locations are not known to be associated with diatom accumulation in cases of drowning.","reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 182.","responses":[{"text":"Gall bladder and liver","correct":false,"visible":false},{"text":"Hilum of right lung and right ear","correct":false,"visible":false},{"text":"Stomach and left lung","correct":false,"visible":false},{"text":"Ileum and under surface of liver","correct":false,"visible":false},{"text":"Brain and bone marrow","correct":true,"visible":false}]},{"id":2398,"text":"A neck infection in front of prevertebral fascia may extend:","explanation":null,"reference":"Sutcliffe P, Lasrado S. Anatomy, head and neck, deep cervical neck fascia. In: StatPearls. StatPearls Publishing; 2022. Accessed May 14, 2022. http://www.ncbi.nlm.nih.gov/books/NBK541091/","responses":[{"text":"Into inferior mediastinum","correct":false,"visible":false},{"text":"Through superior into posterior mediastinum","correct":true,"visible":false},{"text":"Into middle mediastinum","correct":false,"visible":false},{"text":"Into superior mediastinum","correct":false,"visible":false},{"text":"Through superior into anterior mediastinum","correct":false,"visible":false}]},{"id":2406,"text":"A patient with tuberculosis is started on isoniazid (INH) as part of a multidrug regimen. The physician also starts therapy with vitamin B6 at the same time. Which of the following is the main reason for giving the vitamin B6 prophylactically?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 194.","responses":[{"text":"Facilitates INH renal excretion","correct":false,"visible":false},{"text":"Prevents some adverse effects of INH therapy","correct":true,"visible":false},{"text":"Is a cofactor required for activation of INH","correct":false,"visible":false},{"text":"Inhibits metabolism of INH","correct":false,"visible":false},{"text":"Potentiates the antitubercular activity of the INH","correct":false,"visible":false}]},{"id":2407,"text":"The human organ which was first examined by nuclear medicine studies was:","explanation":null,"reference":"1) Historical timeline - snmmi. Accessed May 12, 2022. http://www.snmmi.org/AboutSNMMI/Content.aspx?ItemNumber=4175\r\n\r\n2) Respiratory module, Community-medicine slides, Topic: Nuclear-medicine, Sub-topic: Thyroid.","responses":[{"text":"Brain","correct":false,"visible":false},{"text":"Thyroid","correct":true,"visible":false},{"text":"Pancreas","correct":false,"visible":false},{"text":"Bone","correct":false,"visible":false},{"text":"Heart","correct":false,"visible":false}]},{"id":2408,"text":"A 55-year-old patient suffering from persistent dry cough for the last 2-months due to unknown reasons wants to get a drug without having constipating effects. Which of the following would you prescribe?","explanation":null,"reference":"Whalen K, Finkel R, Panavelil TA. Lippincott Illustrated Reviews: Pharmacology. 6th ed. Lippincott Williams \u0026 Wilkins; 2015: 390.","responses":[{"text":"Physostigmine","correct":false,"visible":false},{"text":"Codeine","correct":false,"visible":false},{"text":"Pholcodine","correct":false,"visible":false},{"text":"Dextromethorphan","correct":true,"visible":false},{"text":"Hydrocodone","correct":false,"visible":false}]},{"id":2442,"text":"Which HLA subtype is involved in the development of sarcoidosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n693.","responses":[{"text":"HLA-A3","correct":false,"visible":false},{"text":"HLA-B8","correct":true,"visible":false},{"text":"HLA-A2","correct":false,"visible":false},{"text":"HLA-B27","correct":false,"visible":false},{"text":"HLA-B1","correct":false,"visible":false}]},{"id":2446,"text":"Which of the following anti-asthmatic drugs is not given by inhalation?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 576.","responses":[{"text":"Tiotropium","correct":false,"visible":false},{"text":"Doxophylline","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Theophylline","correct":true,"visible":false},{"text":"Ipratropium","correct":false,"visible":false}]},{"id":2448,"text":"What is the most likely cause of death by drowning in freshwater?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 177.","responses":[{"text":"Pulmonary edema","correct":false,"visible":false},{"text":"Lung ballooning","correct":false,"visible":false},{"text":"Convulsions","correct":false,"visible":false},{"text":"Atrial fibrillation","correct":false,"visible":false},{"text":"Ventricular fibrillation","correct":true,"visible":false}]},{"id":2453,"text":"Which one of the following is a prophylactic agent used in cases of bronchial asthma that stabilizes mast cells?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 416.","responses":[{"text":"Terbutaline","correct":false,"visible":false},{"text":"Cromolyn","correct":true,"visible":false},{"text":"Metaproterenol","correct":false,"visible":false},{"text":"Ipratropium bromide","correct":false,"visible":false},{"text":"Aminophylline","correct":false,"visible":false}]},{"id":2459,"text":"Which of the following is not a criterion for clinical diagnosis of death?","explanation":null,"reference":"Accessed April 27, 2022. https://academic.oup.com/bja/article/108/suppl_1/i14/237765","responses":[{"text":"Absence of pulse","correct":false,"visible":false},{"text":"Absence of breathing","correct":false,"visible":false},{"text":"A flat electroencephalogram (EEG)","correct":true,"visible":false},{"text":"Fixed dilated pupils","correct":false,"visible":false},{"text":"A loss of brainstem reflexes","correct":false,"visible":false}]},{"id":2460,"text":"There is no limit of exhumation in which of the following countries?","explanation":null,"reference":"Journal of law and social studies(Jlss). Accessed April 27, 2022. https://www.advancelrf.org/wp-content/uploads/2021/06/Vol-3.-No.-1-3.pdf","responses":[{"text":"France","correct":false,"visible":false},{"text":"Pakistan","correct":true,"visible":false},{"text":"Germany","correct":false,"visible":false},{"text":"England","correct":false,"visible":false},{"text":"Australia","correct":false,"visible":false}]},{"id":2461,"text":"When does rigor mortis appear in case of hanging?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 144.","responses":[{"text":"Appears late and long duration","correct":true,"visible":false},{"text":"Appears early and long duration","correct":false,"visible":false},{"text":"Appears early and short duration","correct":false,"visible":false},{"text":"Slowly appears and long duration","correct":false,"visible":false},{"text":"Slowly appears and short duration","correct":false,"visible":false}]},{"id":2462,"text":"Which of the following is a sure sign of death by drowning?","explanation":null,"reference":"(1) Respiratory module; Forensic-medicine lecture slides; Topic: Asphyxia III; Sub-topic: Drowning (copious, whitish frothing).\r\n\r\n(2) Subrahmanyam BV. Parikh’s Textbook of Medical Jurisprudence, Forensic Medicine and Toxicology for Classrooms and Courtrooms. 8th ed. CBS Publishers; 2019: 202.","responses":[{"text":"Postmortem lividity","correct":false,"visible":false},{"text":"Clenched fists","correct":false,"visible":false},{"text":"Froth from mouth","correct":true,"visible":false},{"text":"Distended lungs","correct":false,"visible":false},{"text":"Cadeveric spasms","correct":false,"visible":false}]},{"id":2464,"text":"What is the approximate brain weight of an adult human?","explanation":null,"reference":"Brain weight - an overview | sciencedirect topics. Accessed January 25, 2023. https://www.sciencedirect.com/topics/immunology-and-microbiology/brain-weight","responses":[{"text":"1.0 kg","correct":false,"visible":false},{"text":"2.0 kg","correct":false,"visible":false},{"text":"1.3 kg","correct":false,"visible":false},{"text":"1.5 kg","correct":true,"visible":false},{"text":"2.2 kg","correct":false,"visible":false}]},{"id":2465,"text":"What is the most probable cause of death in a judicial hanging?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 163.","responses":[{"text":"Choking","correct":false,"visible":false},{"text":"Neck fracture","correct":true,"visible":false},{"text":"Skull fracture","correct":false,"visible":false},{"text":"Strangulation","correct":false,"visible":false},{"text":"Asphyxiation","correct":false,"visible":false}]},{"id":2466,"text":"What is the medical term for the yellow, creamy pus in the pleural cavity?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n722.","responses":[{"text":"Pleural exudate","correct":false,"visible":false},{"text":"Pustule","correct":false,"visible":false},{"text":"Pleural transudate","correct":false,"visible":false},{"text":"Emphysema","correct":false,"visible":false},{"text":"Empyema","correct":true,"visible":false}]},{"id":2467,"text":"Pulmonary edema does not occur in which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n671.","responses":[{"text":"Adverse reaction to certain medications","correct":false,"visible":false},{"text":"Pneumonia","correct":false,"visible":false},{"text":"Breast cancer","correct":true,"visible":false},{"text":"Burns","correct":false,"visible":false},{"text":"Sepsis","correct":false,"visible":false}]},{"id":2468,"text":"Which type of infarction is seen in pulmonary infarcts?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n698.","responses":[{"text":"Coagulative","correct":false,"visible":false},{"text":"White","correct":false,"visible":false},{"text":"Hemorrhagic","correct":true,"visible":false},{"text":"Gangrenous","correct":false,"visible":false},{"text":"Ischemic","correct":false,"visible":false}]},{"id":2469,"text":"Which of the following is the most important air pollutant of the greenhouse effect?","explanation":null,"reference":"Air pollution - greenhouse gases | britannica. Accessed April 27, 2022. https://www.britannica.com/science/air-pollution/Greenhouse-gases","responses":[{"text":"Carbon monoxide","correct":false,"visible":false},{"text":"Nitric oxide","correct":false,"visible":false},{"text":"Hydrogen sulphide","correct":false,"visible":false},{"text":"Nitrous oxide","correct":false,"visible":false},{"text":"Carbon dioxide","correct":true,"visible":false}]},{"id":2471,"text":"Mycobacterium tuberculosis can be cultured in which medium?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 124.","responses":[{"text":"Streptococcuseosin methylene blue (EMB)","correct":false,"visible":false},{"text":"Blood agar","correct":false,"visible":false},{"text":"None of the above","correct":false,"visible":false},{"text":"Löwenstein–Jensen","correct":true,"visible":false},{"text":"Chocolate agar","correct":false,"visible":false}]},{"id":2472,"text":"What stain is used for Mycobacterium tuberculosis?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 123.","responses":[{"text":"Hematoxylin and eosin stain","correct":false,"visible":false},{"text":"Congo red capsule stain","correct":false,"visible":false},{"text":"Ziehl–Neelsen stain","correct":true,"visible":false},{"text":"Endospore stain","correct":false,"visible":false},{"text":"Gram-negative stain","correct":false,"visible":false}]},{"id":2473,"text":"Pneumothorax is most commonly associated with which of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n722.","responses":[{"text":"Pleural effusion","correct":false,"visible":false},{"text":"Emphysema","correct":true,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Lung abscess","correct":false,"visible":false},{"text":"Pulmonary embolism","correct":false,"visible":false}]},{"id":2474,"text":"The neck of a person was impacted by 15 kgs of weight. What is the most likely cause of death?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015:\r\n160.","responses":[{"text":"Asphyxiation","correct":true,"visible":false},{"text":"Throttling","correct":false,"visible":false},{"text":"Choking","correct":false,"visible":false},{"text":"Neck fracture","correct":false,"visible":false},{"text":"Strangulation","correct":false,"visible":false}]},{"id":2561,"text":"Which of the following is incorrect about asthma?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 91.","responses":[{"text":"Reversible disease","correct":false,"visible":false},{"text":"Type 1 hypersensitivity","correct":false,"visible":false},{"text":"Communicable disease","correct":true,"visible":false},{"text":"Chronic disease","correct":false,"visible":false},{"text":"Airway hyperreactivity","correct":false,"visible":false}]},{"id":2565,"text":"Which of the following is the most common type of emphysema?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 90.","responses":[{"text":"Panacinar","correct":false,"visible":false},{"text":"Paraseptal","correct":false,"visible":false},{"text":"Centrilobular","correct":true,"visible":false},{"text":"Proximal acinar","correct":false,"visible":false},{"text":"Distal acinar","correct":false,"visible":false}]},{"id":2566,"text":"Which type of emphysema involves proximal airway damage?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 90.","responses":[{"text":"Panacinar","correct":false,"visible":false},{"text":"None of these","correct":false,"visible":false},{"text":"Paraseptal","correct":false,"visible":false},{"text":"Distal acinar","correct":false,"visible":false},{"text":"Centrilobular","correct":true,"visible":false}]},{"id":2570,"text":"Which one of the following is an external sign of antemortem hanging in case of instantaneous death?","explanation":"The external sign of antemortem hanging that is indicative of instantaneous death is **tongue protrusion with saliva dribbling from the mouth**.\r\n\r\nDuring hanging, the constriction of the ligature around the neck can cause pressure on the structures within the throat, leading to obstruction of the airway and subsequent asphyxiation. In cases of instantaneous death, the individual may not have had the opportunity to close their mouth or swallow, resulting in the tongue protruding out of the mouth. Additionally, saliva may accumulate and dribble from the mouth due to the loss of control over the oral muscles.\r\n\r\nThe other options mentioned, such as hemorrhages in the lymph nodes above the ligature mark, bruising, rupture, or laceration of neck soft structures, face and head congestion, and congestion in the lymph nodes above and below the ligature mark, are not specific to instantaneous death and can also be observed in cases of both antemortem and postmortem hanging.","reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 164.","responses":[{"text":"Hemorrhages in the lymph nodes above the ligature mark","correct":false,"visible":false},{"text":"Congestion in the lymph nodes above and below ligature mark","correct":false,"visible":false},{"text":"Face and head above ligature may be congested","correct":false,"visible":false},{"text":"Bruising, rupture, or laceration of neck's soft structures","correct":false,"visible":false},{"text":"Tongue protruding with saliva dribbling from the mouth","correct":true,"visible":false}]},{"id":2571,"text":"What is the most common causative organism of community-acquired pneumonia?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 88.","responses":[{"text":"Staphylococcus aureus","correct":false,"visible":false},{"text":"Klebsiella pneumoniae","correct":false,"visible":false},{"text":"Streptococcus pneumoniae","correct":true,"visible":false},{"text":"Pseudomonas aeruginosa","correct":false,"visible":false},{"text":"Mycoplasma pneumoniae","correct":false,"visible":false}]},{"id":2572,"text":"Which of the following is the correct Light's criteria for LDH serum ratio in exudative pleural effusion?","explanation":"According to Light's criteria, a **pleural effusion** is considered **exudative** if at least one of the following criteria is met:\r\n\r\n- Pleural fluid protein/serum protein ratio greater than 0.5\r\n- Pleural fluid LDH/serum LDH ratio greater than 0.6\r\n- Pleural fluid LDH level greater than two-thirds the upper limit of normal for serum LDH\r\n\r\nThe pleural fluid LDH/serum LDH ratio should be greater than 0.6 IU/ml to classify the pleural effusion as exudative.","reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 564.","responses":[{"text":"Greater than 0.6 IU/ml","correct":true,"visible":false},{"text":"Greater than 0.5 IU/ml","correct":false,"visible":false},{"text":"Less than 0.5 IU/ml","correct":false,"visible":false},{"text":"Less than 0.6 IU/ml","correct":false,"visible":false},{"text":"Less than 0.4 IU/ml","correct":false,"visible":false}]},{"id":2573,"text":"Which of the following is the most common causative organism of pneumonia caused due to faulty air conditioning?","explanation":"The most common causative organism of pneumonia caused due to faulty air conditioning is ***Legionella pneumophila***. Legionella is a type of bacteria that can grow and multiply in water systems, including cooling towers, hot tubs, and **air conditioning systems**. When these systems are not properly maintained or cleaned, Legionella bacteria can be released into the air and inhaled, leading to **Legionnaires' disease**, which is a severe form of pneumonia. \r\n\r\nOther organisms listed, such as *Pseudomonas aeruginosa, Mycoplasma pneumoniae, Staphylococcus aureus*, and *Klebsiella pneumoniae*, may also cause pneumonia in different settings, but they are not specifically associated with pneumonia caused by faulty air conditioning.","reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 141.","responses":[{"text":"Staphylococcus aureus","correct":false,"visible":false},{"text":"Pseudomonas aeruginosa","correct":false,"visible":false},{"text":"Mycoplasma pneumoniae","correct":false,"visible":false},{"text":"Legionella pneumophila","correct":true,"visible":false},{"text":"Klebsiella pneumoniae","correct":false,"visible":false}]},{"id":2574,"text":"Albuterol is known to cause bronchial relaxation by which of the following?","explanation":null,"reference":"Hsu E, Bajaj T. Beta 2 Agonists. In: StatPearls. StatPearls Publishing; 2022. Accessed May 1, 2022. http://www.ncbi.nlm.nih.gov/books/NBK542249/","responses":[{"text":"Accumulation of IP3","correct":false,"visible":false},{"text":"Accumulation of cytosolic calcium","correct":false,"visible":false},{"text":"Accumulation of neurotransmitter acetylcholine","correct":false,"visible":false},{"text":"Accumulation of cGMP","correct":false,"visible":false},{"text":"Accumulation of cAMP","correct":true,"visible":false}]},{"id":2575,"text":"What is the mechanism of action of sodium cromolyn in asthma patients?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 416.","responses":[{"text":"Cytokine inhibitor","correct":false,"visible":false},{"text":"Selective beta-2 agonist","correct":false,"visible":false},{"text":"Mast cell stabilizer","correct":true,"visible":false},{"text":"Bronchodilator","correct":false,"visible":false},{"text":"Leukotriene inhibitor","correct":false,"visible":false}]},{"id":2576,"text":"Which enzyme does albuterol influence during its mechanism of action?","explanation":null,"reference":"Hsu E, Bajaj T. Beta 2 Agonists. In: StatPearls. StatPearls Publishing; 2022. Accessed May 1, 2022. http://www.ncbi.nlm.nih.gov/books/NBK542249/","responses":[{"text":"None of these","correct":false,"visible":false},{"text":"Protein cyclase","correct":false,"visible":false},{"text":"Glutaminyl cyclase","correct":false,"visible":false},{"text":"Adenylyl cyclase","correct":true,"visible":false},{"text":"Guanylyl cyclase","correct":false,"visible":false}]},{"id":2577,"text":"Which type of pneumonia is seen in patients that have a weakened immune system due to the human immunodeficiency virus (HIV)?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 151.","responses":[{"text":"Interstitial pneumonia","correct":false,"visible":false},{"text":"Aspiration pneumonia","correct":false,"visible":false},{"text":"Pneumocystis pneumonia","correct":true,"visible":false},{"text":"Bronchopneumonia","correct":false,"visible":false},{"text":"Lobar pneumonia","correct":false,"visible":false}]},{"id":2578,"text":"Which of the following is a characteristic feature used to diagnose croup?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 167.","responses":[{"text":"Whooping cough","correct":false,"visible":false},{"text":"Barking cough","correct":true,"visible":false},{"text":"Productive cough","correct":false,"visible":false},{"text":"Dry cough","correct":false,"visible":false},{"text":"Post-viral cough","correct":false,"visible":false}]},{"id":2579,"text":"Which of the following drugs is a long-acting beta-agonist used for the treatment of asthma?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 712.","responses":[{"text":"Salmeterol","correct":true,"visible":false},{"text":"Zafirlukast","correct":false,"visible":false},{"text":"Theophylline","correct":false,"visible":false},{"text":"Montelukast","correct":false,"visible":false},{"text":"Albuterol","correct":false,"visible":false}]},{"id":2580,"text":"Which of the following is the mechanism of action of aspirin?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 499.","responses":[{"text":"Increased mast cell activity","correct":false,"visible":false},{"text":"Promotion of cyclooxygenase pathway","correct":false,"visible":false},{"text":"Inhibition of mast cell activity","correct":false,"visible":false},{"text":"Bronchodilation","correct":false,"visible":false},{"text":"Inhibition of cyclooxygenase pathway","correct":true,"visible":false}]},{"id":2581,"text":"Which of the following drugs has both antihistamine and mast cell stabilizing properties?","explanation":null,"reference":"Whalen K, Finkel R, Panavelil TA. Lippincott Illustrated Reviews: Pharmacology. 6th ed. Lippincott Williams \u0026 Wilkins; 2015: 395.","responses":[{"text":"Mometasone","correct":false,"visible":false},{"text":"Fluticasone","correct":false,"visible":false},{"text":"Beclomethasone","correct":false,"visible":false},{"text":"Montelukast","correct":false,"visible":false},{"text":"Ketotifen","correct":true,"visible":false}]},{"id":2636,"text":"What can a saddle embolus lead to?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 39.","responses":[{"text":"Pulmonary hypertension","correct":false,"visible":false},{"text":"Nose bleed","correct":false,"visible":false},{"text":"Sudden death","correct":true,"visible":false},{"text":"Chest pain","correct":false,"visible":false},{"text":"Hemorrhage","correct":false,"visible":false}]},{"id":2655,"text":"Which of the following is an antifolate drug?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 34.","responses":[{"text":"Chloroquine","correct":false,"visible":false},{"text":"Methotrexate","correct":true,"visible":false},{"text":"Amodiaquine","correct":false,"visible":false},{"text":"Halofantrine","correct":false,"visible":false},{"text":"Primaquine","correct":false,"visible":false}]},{"id":2656,"text":"Which of the following is an inhaled corticosteroid prescribed for the treatment of asthma?","explanation":null,"reference":"Whalen K, Finkel R, Panavelil TA. Lippincott Illustrated Reviews: Pharmacology. 6th ed. Lippincott Williams \u0026 Wilkins; 2015: 382.","responses":[{"text":"Methylprednisolone","correct":false,"visible":false},{"text":"Beclomethasone","correct":true,"visible":false},{"text":"Dexamethasone","correct":false,"visible":false},{"text":"Prednisone","correct":false,"visible":false},{"text":"Triamcinolone","correct":false,"visible":false}]},{"id":2657,"text":"Which of the following drugs is a mast cell stabilizer?","explanation":"**Cromoglicic acid** is a medication that helps prevent the release of inflammatory substances, such as histamine, from mast cells. It is commonly used in the treatment of asthma and allergic conditions, including allergic rhinitis and allergic conjunctivitis.\r\n\r\nLoratadine, clemastine, chlorpheniramine, and diphenhydramine, are antihistamines that block the effects of histamine after it has been released. While they can help relieve allergy symptoms, they do not directly stabilize mast cells like cromoglicic acid.","reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 416.","responses":[{"text":"Diphenhydramine","correct":false,"visible":false},{"text":"Loratadine","correct":false,"visible":false},{"text":"Cromoglicic acid","correct":true,"visible":false},{"text":"Chlorpheniramine","correct":false,"visible":false},{"text":"Clemastine","correct":false,"visible":false}]},{"id":2659,"text":"Which of the following drugs can lead to vestibular toxicity as an adverse effect?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 194.","responses":[{"text":"Doxycycline","correct":false,"visible":false},{"text":"Amoxicillin","correct":false,"visible":false},{"text":"Cephalexin","correct":false,"visible":false},{"text":"Ciprofloxacin","correct":false,"visible":false},{"text":"Streptomycin","correct":true,"visible":false}]},{"id":2660,"text":"Which of the following drugs acts as a mucolytic agent?","explanation":null,"reference":"Sadowska AM, Verbraecken J, Darquennes K, De Backer W. Role of N-acetylcysteine in the management of COPD. Int J Chron Obstruct Pulmon Dis. 2006;1(4):425-434. Accessed May 6, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC2707813/","responses":[{"text":"Tramadol","correct":false,"visible":false},{"text":"Acetaminophen","correct":false,"visible":false},{"text":"Acetylcysteine","correct":true,"visible":false},{"text":"Acetylsalicylic acid","correct":false,"visible":false},{"text":"Oxycodone","correct":false,"visible":false}]},{"id":2661,"text":"Which of the following drugs is used in isolated therapy for uncomplicated tuberculosis (TB)?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 194.","responses":[{"text":"Rifampin","correct":false,"visible":false},{"text":"Ethambutol","correct":false,"visible":false},{"text":"Pyrazinamide","correct":false,"visible":false},{"text":"Isoniazid","correct":true,"visible":false},{"text":"Bedaquiline","correct":false,"visible":false}]},{"id":2665,"text":"Which of the following lung cancers arises from neurosecretory cells?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 96.","responses":[{"text":"Bronchioalveolar carcinoma","correct":false,"visible":false},{"text":"Small cell carcinoma","correct":true,"visible":false},{"text":"Adenocarcinoma","correct":false,"visible":false},{"text":"Large cell carcinoma","correct":false,"visible":false},{"text":"Squamous cell carcinoma","correct":false,"visible":false}]},{"id":2666,"text":"Which of these is the most common type of lung cancer?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 96.","responses":[{"text":"Large cell carcinoma","correct":false,"visible":false},{"text":"Squamous cell carcinoma","correct":false,"visible":false},{"text":"Carcinoid tumor","correct":false,"visible":false},{"text":"Adenocarcinoma","correct":true,"visible":false},{"text":"Small cell carninoma","correct":false,"visible":false}]},{"id":2668,"text":"Hemoptysis is commonly seen in which type of lung cancer?","explanation":null,"reference":"Gershman E, Guthrie R, Swiatek K, Shojaee S. Management of hemoptysis in patients with lung cancer. Annals of Translational Medicine. Published August 2019. Accessed May 6, 2022. https://atm.amegroups.com/article/view/25685","responses":[{"text":"Large cell carcinoma","correct":false,"visible":false},{"text":"Bronchioalveolar carcinoma","correct":false,"visible":false},{"text":"Squamous cell carcinoma","correct":true,"visible":false},{"text":"Adenocarcinoma","correct":false,"visible":false},{"text":"Small cell carcinoma","correct":false,"visible":false}]},{"id":2670,"text":"Which of the following arteries is most commonly blocked in autopsy in case of coronary atherosclerosis?","explanation":"The most commonly blocked artery in cases of coronary atherosclerosis is the **left anterior descending artery (LAD)**. The LAD supplies a large portion of the left ventricle, including the anterior wall, septum, and apex of the heart. It is a major branch of the left coronary artery and is susceptible to plaque buildup and narrowing, leading to reduced blood flow and potentially causing a heart attack.","reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 132.","responses":[{"text":"Left subclavian artery","correct":false,"visible":false},{"text":"Right marginal artery","correct":false,"visible":false},{"text":"Left anterior descending artery","correct":true,"visible":false},{"text":"Right coronary artery","correct":false,"visible":false},{"text":"Circumflex artery","correct":false,"visible":false}]},{"id":2674,"text":"The gene most often altered in squamous cell cancers is which one of the following?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n713, 714.","responses":[{"text":"NSCLC","correct":false,"visible":false},{"text":"KRAS","correct":false,"visible":false},{"text":"TP58","correct":false,"visible":false},{"text":"EGFR","correct":false,"visible":false},{"text":"TP53","correct":true,"visible":false}]},{"id":2682,"text":"Which is the most common lung cancer seen in women?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 96.","responses":[{"text":"Bronchioalveolar carcinoma","correct":false,"visible":false},{"text":"Small cell carcinoma","correct":false,"visible":false},{"text":"Adenocarcinoma","correct":true,"visible":false},{"text":"Large cell carcinoma","correct":false,"visible":false},{"text":"Squamous cell carcinoma","correct":false,"visible":false}]},{"id":2684,"text":"Which lung carcinoma is related to the adrenocorticotrophic hormone (ACTH)?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 96.","responses":[{"text":"Small cell carcinoma","correct":true,"visible":false},{"text":"Squamous cell carcinoma","correct":false,"visible":false},{"text":"Adenocarcinoma","correct":false,"visible":false},{"text":"Large cell carcinoma","correct":false,"visible":false},{"text":"Bionchioalveolar carcinoma","correct":false,"visible":false}]},{"id":2687,"text":"Which of the following organisms most commonly causes atypical pneumonia?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 88.","responses":[{"text":"Streptococcus pneumoniae","correct":false,"visible":false},{"text":"Mycoplasma pneumoniae","correct":true,"visible":false},{"text":"Chlamydia pneumoniae","correct":false,"visible":false},{"text":"Legionella pneumophila","correct":false,"visible":false},{"text":"Pseudomonas aeruginosa","correct":false,"visible":false}]},{"id":2690,"text":"A 20-year-old man comes to the outpatient clinic with a complaint of flu-like symptoms. He is diagnosed with pneumonia, showing bilateral lung infiltrates. What is the causative organism in this case?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 88.","responses":[{"text":"Streptococcus pneumoniae","correct":false,"visible":false},{"text":"Pseudomonas aeruginosa","correct":false,"visible":false},{"text":"Klebsiella pneumoniae","correct":false,"visible":false},{"text":"Staphylococcus aureus","correct":true,"visible":false},{"text":"Haemophilus influenzae","correct":false,"visible":false}]},{"id":2691,"text":"A 25-year-old man suffering from a respiratory illness is advised by the doctor to get a chest X-ray. There are pleural plaques seen on his x-ray. These plaques are indicative of which disease?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 93.","responses":[{"text":"Asbestosis","correct":true,"visible":false},{"text":"Pneumonia","correct":false,"visible":false},{"text":"Pneumothorax","correct":false,"visible":false},{"text":"Pleural effusion","correct":false,"visible":false},{"text":"Small cell carcinoma","correct":false,"visible":false}]},{"id":2692,"text":"In which of the following diseases fibrosis on lung CT is initially seen in subpleural patches, but eventually results in diffuse fibrosis with end-stage 'honeycomb' lung?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 92.","responses":[{"text":"Idiopathic pulmonary fibrosis","correct":true,"visible":false},{"text":"Pneumoconioses","correct":false,"visible":false},{"text":"Silicosis","correct":false,"visible":false},{"text":"Sarcoidosis","correct":false,"visible":false},{"text":"Hypersensitivity pneumonitis","correct":false,"visible":false}]},{"id":2694,"text":"Hypersensitivity pneumonitis can be caused by which of the following?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 94.","responses":[{"text":"Cigarette smoke","correct":false,"visible":false},{"text":"Alcohol","correct":false,"visible":false},{"text":"Perfume vapours","correct":false,"visible":false},{"text":"Animal droppings","correct":false,"visible":false},{"text":"Organic dust","correct":true,"visible":false}]},{"id":2695,"text":"While reading an x-ray, a doctor observes eggshell calcifications in the lungs. This condition is caused by exposure to which of the following agents?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 702.","responses":[{"text":"Cigarette smoke","correct":false,"visible":false},{"text":"Asbestos","correct":false,"visible":false},{"text":"Alcohol","correct":false,"visible":false},{"text":"Organic dust","correct":false,"visible":false},{"text":"Silica","correct":true,"visible":false}]},{"id":2735,"text":"Which of the following conditions is most likely to cause sudden death?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 39.","responses":[{"text":"Lung abscess","correct":false,"visible":false},{"text":"Pulmonary hemorrhage","correct":false,"visible":false},{"text":"Pulmonary thrombus","correct":false,"visible":false},{"text":"Saddle embolus","correct":true,"visible":false},{"text":"Pulmonary hypertension","correct":false,"visible":false}]},{"id":2737,"text":"A patient's pulmonary function test shows FEVI/FVC \u003e 0.7 and FEV1 100% of predicted with decreased total lung capacity (TLC). Which of the following patterns is this?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 92.","responses":[{"text":"Non-specific reductions in FEVI and FVC","correct":false,"visible":false},{"text":"Mixed pattern","correct":false,"visible":false},{"text":"Normal pattern","correct":false,"visible":false},{"text":"Obstructive pattern","correct":false,"visible":false},{"text":"Restrictive pattern","correct":true,"visible":false}]},{"id":2739,"text":"A 27-year-old patient got a chest X-ray which showed a round thick-walled cavity with an air-fluid level, and surrounding consolidation. Which of the following is the most likely cause of this patient's condition?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n702, 708, 709.","responses":[{"text":"Foreign body inhalation","correct":false,"visible":false},{"text":"Antecedent infection","correct":false,"visible":false},{"text":"Lung infection","correct":false,"visible":false},{"text":"Trauma","correct":false,"visible":false},{"text":"Aspiration pneumonia","correct":true,"visible":false}]},{"id":2740,"text":"Which of the following is not associated with triggering or increasing the risk of developing asthma?","explanation":null,"reference":"(1) Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 680, 681. (2) El-Heneidy A, Abdel-Rahman ME, Mihala G, Ross LJ, Comans TA. Milk other than breast milk and the development of asthma in children 3 years of age. A birth cohort study(2006–2011). Nutrients. Published November 19, 2018. Accessed May 7, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC6267177/","responses":[{"text":"Formula feeding instead of breastmilk","correct":false,"visible":false},{"text":"Low population density","correct":true,"visible":false},{"text":"Parental asthma","correct":false,"visible":false},{"text":"Childhood respiratory syncytial virus infection","correct":false,"visible":false},{"text":"Childhood tuberculosis infection","correct":false,"visible":false}]},{"id":2741,"text":"Which of the following is a triggering factor for asthma?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: 681.","responses":[{"text":"Childhood respiratory syncytial virus (RSV) infection","correct":true,"visible":false},{"text":"All of these","correct":false,"visible":false},{"text":"The predominance of lactobacilli in the gut","correct":false,"visible":false},{"text":"Childhood infection with parasites","correct":false,"visible":false},{"text":"Living on farm","correct":false,"visible":false}]},{"id":2743,"text":"Why is a 'Y' shaped incision made during an autopsy?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 103.","responses":[{"text":"To study the abdominal structures","correct":false,"visible":false},{"text":"To gain access to pelvic structures","correct":false,"visible":false},{"text":"To perform a lung dissection","correct":false,"visible":false},{"text":"To perform a heart dissection","correct":false,"visible":false},{"text":"To allow maximum approach to neck structures","correct":true,"visible":false}]},{"id":2744,"text":"Which of the following is an example of pericellular histotoxic type of asphyxia?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 131.\r\n\r\nTextbook of Forensic Medicine and Toxicology by Nageshkumar G Rao, 2nd edition, page no. 195","responses":[{"text":"Carbon monoxide poisoning","correct":false,"visible":false},{"text":"Opiates poisoning","correct":false,"visible":false},{"text":"Cardiac arrest","correct":false,"visible":false},{"text":"Chloroform poisoning","correct":true,"visible":false},{"text":"Cyanide poisoning","correct":false,"visible":false}]},{"id":2745,"text":"Despite a thorough postmortem physical examination, chemical analysis, and microscopic examination, sometimes the cause of death cannot be arrived at. What is this called?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 116.","responses":[{"text":"Hidden autopsy","correct":false,"visible":false},{"text":"Unknown autopsy","correct":false,"visible":false},{"text":"Negative autopsy","correct":true,"visible":false},{"text":"False autopsy","correct":false,"visible":false},{"text":"Positive autopsy","correct":false,"visible":false}]},{"id":2759,"text":"Which of the following organs is not dissected in detail during autopsy?","explanation":"During an autopsy, the **spinal cord** is not typically dissected in detail. The focus of an autopsy is primarily on examining the organs and tissues within the body to determine the cause of death and any underlying diseases or conditions. While the brain, lungs, kidneys, and heart are commonly examined during an autopsy, the spinal cord is not routinely dissected unless there is a specific indication to do so, such as suspected spinal cord injury or disease.","reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 110.","responses":[{"text":"Brain","correct":false,"visible":false},{"text":"Spinal cord","correct":true,"visible":false},{"text":"Lungs","correct":false,"visible":false},{"text":"Heart","correct":false,"visible":false},{"text":"Kidneys","correct":false,"visible":false}]},{"id":2760,"text":"Which bones help in determining the sex of an individual?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 64.","responses":[{"text":"Femur","correct":false,"visible":false},{"text":"Skull and femur","correct":false,"visible":false},{"text":"Mandible and femur","correct":false,"visible":false},{"text":"Skull and pelvis","correct":true,"visible":false},{"text":"Pelvis","correct":false,"visible":false}]},{"id":2761,"text":"Where is the incision for an autopsy of the head made?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 108.","responses":[{"text":"From one temple to the other temple till the occipital notch","correct":false,"visible":false},{"text":"From one mastoid to the other mastoid till the base of skull","correct":false,"visible":false},{"text":"The location of the incision does not matter","correct":false,"visible":false},{"text":"From one temple to the other temple till the base of skull","correct":false,"visible":false},{"text":"From one mastoid to the other mastoid till the occipital notch","correct":true,"visible":false}]},{"id":2762,"text":"Which of the following radiological methods is the best way to diagnose desquamative interstitial pneumonia?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 606, 607.","responses":[{"text":"Magnetic resonance imaging","correct":false,"visible":false},{"text":"Chest x-ray","correct":false,"visible":false},{"text":"Fluoroscopy","correct":false,"visible":false},{"text":"High-resolution computed tomography (HRCT)","correct":true,"visible":false},{"text":"Ultrasound","correct":false,"visible":false}]},{"id":2763,"text":"Which of the following best describes the radiological findings in the case of desquamative interstitial pneumonia?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n696.","responses":[{"text":"Scattered, patchy consolidation","correct":false,"visible":false},{"text":"Multifocal consolidation","correct":false,"visible":false},{"text":"Honeycomb-like appearance","correct":false,"visible":false},{"text":"Fibrosis","correct":false,"visible":false},{"text":"Diffuse interstitial infiltrates","correct":true,"visible":false}]},{"id":2770,"text":"Why is pyridoxine given in combination with isoniazid?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 194.","responses":[{"text":"Because both of these have the same therapeutic effect","correct":false,"visible":false},{"text":"To reduce its bioavailability","correct":false,"visible":false},{"text":"To increase its bioavailability","correct":false,"visible":false},{"text":"To potentiate the drug","correct":false,"visible":false},{"text":"To avoid side effects","correct":true,"visible":false}]},{"id":2771,"text":"Which of the following are rarely given to asthma patients?","explanation":null,"reference":"Whalen K, Finkel R, Panavelil TA. Lippincott Illustrated Reviews: Pharmacology. 6th ed. Lippincott Williams \u0026 Wilkins; 2015: 385.","responses":[{"text":"Leukotriene modifiers","correct":false,"visible":false},{"text":"Oral corticosteroids","correct":true,"visible":false},{"text":"Long-acting β-agonists (LABA)","correct":false,"visible":false},{"text":"Short-acting β-agonists (SABA)","correct":false,"visible":false},{"text":"Inhaled corticosteroids","correct":false,"visible":false}]},{"id":2772,"text":"Which of the following is not given for productive cough?","explanation":null,"reference":"Karen Whalen, Radhakrishnan R, Field C. Lippincott Illustrated Reviews: Pharmacology. 7th ed. Lippincott Williams \u0026 Wilkins; 2019: 528.","responses":[{"text":"Dextromethorphan","correct":true,"visible":false},{"text":"Acetylcysteine","correct":false,"visible":false},{"text":"Vasaka","correct":false,"visible":false},{"text":"Guaiacol","correct":false,"visible":false},{"text":"Bromhexine","correct":false,"visible":false}]},{"id":2773,"text":"A 16-year-old boy develops fever with chills and a productive cough. What is the most likely diagnosis?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n705.","responses":[{"text":"Atypical pneumonia","correct":false,"visible":false},{"text":"Nosocomial pneumonia","correct":false,"visible":false},{"text":"Health care associated pneumonia","correct":false,"visible":false},{"text":"Community-acquired pneumonia","correct":true,"visible":false},{"text":"Bronchopneumonia","correct":false,"visible":false}]},{"id":2774,"text":"A 31-year-old patient who is immunocompromised due to acquired immunodeficiency syndrome (AIDS) will develop pneumonia caused by which of the following organisms?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 151.","responses":[{"text":"Pneumocystis carinii","correct":true,"visible":false},{"text":"Chlamydia pneumoniae","correct":false,"visible":false},{"text":"Haemophilus influenzae","correct":false,"visible":false},{"text":"Legionella pneumophila","correct":false,"visible":false},{"text":"Mycoplasma pneumoniae","correct":false,"visible":false}]},{"id":2777,"text":"A 3-year-old boy is brought with complaints of difficulty in breathing, noisy harsh sounds produced during inspiration, and high-grade fever for 2 days.  What will be the finding on his chest X-ray?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 140.","responses":[{"text":"Collar's sign","correct":false,"visible":false},{"text":"Continuous diaphragm sign","correct":false,"visible":false},{"text":"Cottage loaf sign","correct":false,"visible":false},{"text":"Steeple sign","correct":false,"visible":false},{"text":"Thumbprinting sign","correct":true,"visible":false}]},{"id":2778,"text":"A 3-year-old boy is brought with complaints of difficulty in breathing, noisy harsh sounds produced during inspiration, and high-grade fever for 2 days. What will be the most important step in management?","explanation":null,"reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 140.","responses":[{"text":"Racemic epinephrine","correct":false,"visible":false},{"text":"Antibiotics","correct":true,"visible":false},{"text":"Hydration","correct":false,"visible":false},{"text":"Intravenous dextrose","correct":false,"visible":false},{"text":"Intravenous normal saline","correct":false,"visible":false}]},{"id":2779,"text":"A 3-year-old boy is brought with complaints of difficulty in breathing, noisy harsh sounds produced during inspiration, and high-grade fever for 2 days. Which of the following is the most likely causative organism causing this condition?","explanation":"The most likely causative organism causing the symptoms described in the 3-year-old boy is ***Haemophilus influenzae*** **type b (Hib)**. Hib is known to cause **acute epiglottitis**, which presents with symptoms such as difficulty in breathing, noisy harsh sounds during inspiration (stridor), and high fever. Epiglottitis is a severe infection of the epiglottis and surrounding tissues, and Hib is the most common bacterial cause of this condition in children. It is important to note that routine immunization with the Hib vaccine has significantly reduced the incidence of Hib-related infections.","reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 85.","responses":[{"text":"Streptococcus viridans","correct":false,"visible":false},{"text":"Haemophilus influenza type a","correct":false,"visible":false},{"text":"Streptococcus pneumoniae","correct":false,"visible":false},{"text":"Staphylococcus aureus","correct":false,"visible":false},{"text":"Haemophilus influenza type b","correct":true,"visible":false}]},{"id":2800,"text":"Which of these screening tests is most commonly used to diagnose tuberculosis?","explanation":null,"reference":"Tuberculosis - diagnosis and treatment - mayo clinic. Accessed May 11, 2022. https://www.mayoclinic.org/diseases-conditions/tuberculosis/diagnosis-treatment/drc-20351256","responses":[{"text":"Polymerase chain reaction (PCR)","correct":false,"visible":false},{"text":"Chest X-ray","correct":false,"visible":false},{"text":"Sputum culture test","correct":false,"visible":false},{"text":"Tuberculin skin test","correct":true,"visible":false},{"text":"Bacilus Calmette-Guerin (BCG)","correct":false,"visible":false}]},{"id":2801,"text":"Which of the following is a centrally acting antitussive?","explanation":null,"reference":"Noscapine - an overview | sciencedirect topics. Accessed April 17, 2022. https://www.sciencedirect.com/topics/agricultural-and-biological-sciences/noscapine","responses":[{"text":"Prenoxdiazine","correct":false,"visible":false},{"text":"Bromhexine","correct":false,"visible":false},{"text":"Potassium iodide","correct":false,"visible":false},{"text":"Acetylcysteine","correct":false,"visible":false},{"text":"Noscapine","correct":true,"visible":false}]},{"id":2802,"text":"A pregnant woman has severe asthma. She neglects her treatment by not taking her inhaled corticosteroids. Which of the following is most likely to happen?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 570.","responses":[{"text":"Pulmonary hemorrhage","correct":false,"visible":false},{"text":"Severe cardiac problems","correct":false,"visible":false},{"text":"Hypotension","correct":false,"visible":false},{"text":"Growth retardation","correct":false,"visible":false},{"text":"Maternal eclampsia","correct":true,"visible":false}]},{"id":2803,"text":"How does the volume of dead space change with age?","explanation":null,"reference":"harma G, Goodwin J. Effect of aging on respiratory system physiology and immunology. Clin Interv Aging. 2006;1(3):253-260. Accessed May 11, 2022. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC2695176/","responses":[{"text":"Marked increase","correct":false,"visible":false},{"text":"No change","correct":false,"visible":false},{"text":"Increaes slightly","correct":true,"visible":false},{"text":"Marked reduction","correct":false,"visible":false},{"text":"Reduces slightly","correct":false,"visible":false}]},{"id":2804,"text":"Which of the following is not included in the diagnostic criteria of pulmonary hypertension?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n699.","responses":[{"text":"Pulmonary vascular resistance \u003e 240 dynes/s/cm(-5)","correct":false,"visible":false},{"text":"Mean pulmonary artery pressure \u003e 30 mmHg with exercise","correct":false,"visible":false},{"text":"Pulmonary capillary wedge pressure \u003c 15mmHg","correct":false,"visible":false},{"text":"Mean pulmonary artery pressure \u003e 30 mmHg at rest","correct":true,"visible":false},{"text":"Mean pulmonary artery pressure \u003e 25 mmHg at rest","correct":false,"visible":false}]},{"id":2805,"text":"Which of the following is correct regarding bronchial carcinoma?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 603.","responses":[{"text":"Endobronchial stents are used for pleural effusion","correct":false,"visible":false},{"text":"Radiotherapy is given to alleviate bone pain in primary lung cancer","correct":true,"visible":false},{"text":"Chemotherapy side-effects can be treated with 5-HT3 receptor agonists","correct":false,"visible":false},{"text":"The overall prognosis in bronchial carcinoma is good","correct":false,"visible":false},{"text":"Bronchoscopic laser treatment is not useful","correct":false,"visible":false}]},{"id":2806,"text":"A 24-year-old patient with asthma has a peak expiratory flow (PEF) of 25%, FEV1 (predicted \u003e 80%), with diurnal asthma episodes greater than 2 per week, and nocturnal episodes greater than 2 per month. He is currently on beta-agonists and inhaled corticosteroids (ICS). Which type of asthma is he suffering from?","explanation":null,"reference":"Ralston SH, Penman ID, Strachan MWJ, Hobson RP, eds. Davidson’s Principles and Practice of Medicine. 23rd ed. Elsevier; 2018: 568.","responses":[{"text":"Severe nocturnal asthma","correct":false,"visible":false},{"text":"Mild intermittent asthma","correct":false,"visible":false},{"text":"Severe persistent asthma","correct":false,"visible":false},{"text":"Mild persistent asthma","correct":true,"visible":false},{"text":"Moderate persistent asthma","correct":false,"visible":false}]},{"id":2807,"text":"A 41-year-old man with a history of hypoglycemia goes to the doctor for a routine check. A chest X-ray shows an abnormal mass attached by a pedicle. What is the most likely condition?","explanation":null,"reference":"Kumar V, Abbas AK, Aster JC. Robbins and Cotran Pathologic Basis of Disease. 9th ed. Elsevier Saunders; 2015: \r\n723.","responses":[{"text":"Carcinoid tumor","correct":false,"visible":false},{"text":"Sarcoidosis","correct":false,"visible":false},{"text":"Malignant mesothelioma","correct":false,"visible":false},{"text":"Abscess","correct":false,"visible":false},{"text":"Solitary fibrous nodule","correct":true,"visible":false}]},{"id":2808,"text":"A man has been working at a silica factory for the last 15 years. He develops tuberculosis. Inhibition of which of the following cell line in his lungs made him more susceptible to developing tuberculosis?","explanation":null,"reference":"Sattar HA. Fundamentals of Pathology: Medical Course and Step 1 Review. Pathoma.com; 2021: 93.","responses":[{"text":"Eosinophils","correct":false,"visible":false},{"text":"Basophils","correct":false,"visible":false},{"text":"Neutrophils","correct":false,"visible":false},{"text":"Macrophages","correct":true,"visible":false},{"text":"Lymphocytes","correct":false,"visible":false}]},{"id":2809,"text":"Why is dextromethorphan an antitussive drug?","explanation":"**Dextromethorphan** is an **antitussive** drug because it increases the threshold for cough. Coughing is a reflex mechanism initiated by stimulation of cough receptors in the airways. These receptors can be triggered by various factors such as irritants, inflammation, or excess mucus production.\r\n\r\nDextromethorphan acts on the cough center in the brain, specifically the medullary cough center, and raises the threshold at which the brain responds to the cough reflex. By increasing this threshold, dextromethorphan reduces the frequency and intensity of coughing. It does not directly suppress the production of mucus or reduce the underlying cause of coughing but instead provides temporary relief by reducing the urge to cough.","reference":"Antitussive agent - an overview | sciencedirect topics. Accessed May 12, 2022. https://www.sciencedirect.com/topics/medicine-and-dentistry/antitussive-agent","responses":[{"text":"It increases the threshold for cough","correct":true,"visible":false},{"text":"It is an NMDA receptor agonist","correct":false,"visible":false},{"text":"It increases the intensity of dry cough","correct":false,"visible":false},{"text":"It reduces productive cough","correct":false,"visible":false},{"text":"It inhibits the activity of cilia","correct":false,"visible":false}]},{"id":2810,"text":"Which of the following is a folate antagonist?","explanation":null,"reference":"PubChem. 4-Aminosalicylic acid. Accessed May 12, 2022. https://pubchem.ncbi.nlm.nih.gov/compound/4649","responses":[{"text":"Primaquine","correct":false,"visible":false},{"text":"Amodiaquine","correct":false,"visible":false},{"text":"Halofantrine","correct":false,"visible":false},{"text":"Para-aminosalicylic acid (PAS)","correct":true,"visible":false},{"text":"Chloroquine","correct":false,"visible":false}]},{"id":2811,"text":"A physician prescribed an anti-tuberculosis drug to a patient. He started feeling a tingling sensation. What could you give to reverse this effect?","explanation":"The likely cause of paresthesia and tingling sensation in the hands and feet in this patient receiving anti-tuberculosis therapy (ATT) is **peripheral neuritis**. Peripheral neuritis refers to inflammation of the peripheral nerves, and it can be a side effect of **isoniazid**, which is commonly used in ATT regimens for tuberculosis.\r\n\r\nTo prevent or manage peripheral neuritis associated with isoniazid therapy, it is recommended to supplement with **pyridoxine (vitamin B6)** concurrently. This helps to counteract the deficiency and reduce the risk of nerve damage.\r\n\r\nIsoniazid is known to cause peripheral neuropathy, particularly due to its effect on vitamin B6 (pyridoxine) metabolism. Isoniazid can lead to pyridoxine deficiency, which is essential for nerve function and maintenance. The deficiency of pyridoxine can result in nerve damage, leading to symptoms such as paresthesia, tingling, and sensory disturbances in the hands and feet.","reference":"Le T, Bhushan V. First Aid for the USMLE Step 1 2022. 32nd ed. McGraw-Hill Education; 2022: 65.","responses":[{"text":"Folate","correct":false,"visible":false},{"text":"Vitamin A","correct":false,"visible":false},{"text":"Vitamin B12","correct":false,"visible":false},{"text":"Vitamin C","correct":false,"visible":false},{"text":"Vitamin B6","correct":true,"visible":false}]},{"id":2813,"text":"Surgical intervention is required in which of the following?","explanation":null,"reference":"Giller DB, Scherbakova GV, Giller BD, Khanin AL, Nikolenko VN, Sinelnikov MY. Surgical treatment of bilateral vanishing lung syndrome: a case report. Journal of Cardiothoracic Surgery. Published July 29, 2020. Accessed May 12, 2022. https://doi.org/10.1186/s13019-020-01246-4","responses":[{"text":"Mild persistent asthma","correct":false,"visible":false},{"text":"Bullous emphysema","correct":true,"visible":false},{"text":"Severe asthma","correct":false,"visible":false},{"text":"Bronchiectasis","correct":false,"visible":false},{"text":"Chronic bronchitis","correct":false,"visible":false}]},{"id":2815,"text":"Which of the following types of hanging is suspected in the setting of a male lying naked on the bed in a pornographic setting?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 184.","responses":[{"text":"Lynching","correct":false,"visible":false},{"text":"Autoerotic hanging","correct":true,"visible":false},{"text":"Accidental hanging","correct":false,"visible":false},{"text":"Judicial hanging","correct":false,"visible":false},{"text":"Homicidal hanging","correct":false,"visible":false}]},{"id":3933,"text":"What is the antidote for phenol?","explanation":null,"reference":"Biswas G. Review of Forensic Medicine and Toxicology. 3rd ed. Jaypee Brothers Medical Publishers; 2015: 431.","responses":[{"text":"Ethanol","correct":false,"visible":false},{"text":"Lime water","correct":false,"visible":false},{"text":"Castor oil","correct":true,"visible":false},{"text":"Milk of magnesia","correct":false,"visible":false},{"text":"Sodium bicarbonate","correct":false,"visible":false}]},{"id":10807,"text":"A 20-year-old male presents to the clinic with the complaint of fever for 5 days. Chest examination reveals dull percussion notes and decreased breath sounds in the left lung base. What is the most likely diagnosis?","explanation":null,"reference":"Karkhanis VS, Joshi JM. Pleural effusion: diagnosis, treatment, and management. Open Access Emergency Medicine : OAEM. Published June 22, 2012. Accessed January 26, 2023. https://www.ncbi.nlm.nih.gov/pmc/articles/PMC4753987/","responses":[{"text":"Pulmonary edema","correct":false,"visible":false},{"text":"Lung collapse","correct":false,"visible":false},{"text":"Pneumothorax","correct":false,"visible":false},{"text":"Pleural effusion","correct":true,"visible":false},{"text":"Pulmonary embolism","correct":false,"visible":false}]}
]

export default a